int ans = INT_MAX;

void recur(vector<int> p,vector<int> s,int i,int k) {
    if(i == p.size())
        return;

    if(k == 1) {
        s.push_back(p.back() - p[i]);
        int m = *max_element(s.begin(),s.end());
        int n = *min_element(s.begin(),s.end());
        ans = min(ans, abs(m - n));
        s.pop_back();
        return;
    }

    for (int j = i + 1; j < p.size();j++) {
        int sum = p[j] - p[i];
        s.push_back(sum);
        recur(p,s,j,k - 1);
        s.pop_back();
    }
}

int main() {
    vector<int> n = {3,2,11,12,5,5,9};
    vector<int> p(n.size() + 1,0);
    for (int i = 1; i <= n.size();i++) {
        p[i] = p[i - 1] + n[i - 1];
    }
    vector<int> v;
    recur(p,v,0,4);
    cout << ans << endl;
}
