long long calculate(int arr[],int n){
   long long sumArr[n+1];
   sumArr[0]=0;
   for(int i=1;i<=n;i++)
    sumArr[i]=sumArr[i-1]+arr[i-1] ;

   long long ans=sumArr[n];
   long long l=0,r=sumArr[n];
   pair<long long ,long long>p={1,1} ;
   while(l<=r){
